12		"forge-cli/internal/cmd/base"
13		"forge-cli/pkg/e2eprobe"
14		"forge-cli/pkg/feature"
15		"forge-cli/pkg/forgeconfig"
16		"forge-cli/pkg/just"
17		"forge-cli/pkg/project"
18		"forge-cli/pkg/task"
19		tmpl "forge-cli/pkg/template"
20		"forge-cli/pkg/testrunner"
21	
22		"github.com/spf13/cobra"
23	)
24	
25	// testRunFunc is the signature for running project tests.
26	// Returns (output, success).
27	type testRunFunc func(projectRoot string) (string, bool)
28	
29	var qualityGateVerbose bool
30	
31	// maxFixTasksPerStep caps the number of active fix-tasks per quality-gate step.
32	// When this limit is reached, no new fix-tasks are created for that step.
33	const maxFixTasksPerStep = 3
34	
35	// ErrMaxFixTasks is returned when the maximum number of active fix-tasks for a
36	// quality-gate step has been reached.
37	var ErrMaxFixTasks = errors.New("max fix-tasks reached")
38	
39	var qualityGateCmd = &cobra.Command{
40		Use:   "quality-gate",
41		Short: "Check if all tasks are done, then run tests",
42		Long: `Checks if every task in the current feature is completed or skipped.
43	Exits 0 silently if any task is still pending, in_progress, or blocked (no-op).
44	If all done: runs project-wide unit tests, then test regression.
45	
46	Feature test scripts are run by T-test-run (run-test task), not this hook.
47	This hook is the project health gate: unit tests + regression suite.
48	
49	Use -v to see why the command exits early (useful for debugging).`,
50		Args: cobra.NoArgs,
51		RunE: runQualityGate,
52	}
53	
54	func init() {
55		qualityGateCmd.Flags().BoolVarP(&qualityGateVerbose, "verbose", "v", false, "print debug info when exiting early")
56	}
57	
58	// AllCompletedResult holds context for running tests after all tasks complete.
59	type AllCompletedResult struct {
60		FeatureSlug string
61		ProjectRoot string
62		DocsOnly    bool // true if no implementation or fix tasks exist
63	}
64	
65	// checkAllCompleted verifies all tasks are done and returns test context.
66	// Returns (nil, nil) when tasks are not all done — caller should exit silently.
67	// Returns (nil, error) for infrastructure failures (no project, no feature).
68	func checkAllCompleted(verbose bool) (*AllCompletedResult, error) {
69		projectRoot, err := project.FindProjectRoot()
70		if err != nil {
71			Debugf(verbose, "project root not found: %v", err)
72			return nil, base.ErrProjectNotFound()
73		}
74		Debugf(verbose, "project root: %s", projectRoot)
75	
76		featureSlug, err := feature.GetCurrentFeature(projectRoot)
77		if err != nil {
78			Debugf(verbose, "feature not found: %v", err)
79			return nil, base.ErrFeatureNotSet()
80		}
81		Debugf(verbose, "feature: %s", featureSlug)
82	
83		// Guard: only proceed if .forge/state.json signals allCompleted.
84		forgeState := feature.ReadForgeState(projectRoot)
85		if forgeState == nil || !forgeState.AllCompleted {
86			Debugf(verbose, "no forge state with allCompleted — skipping")
87			return nil, nil
88		}
89		Debugf(verbose, "forge state: feature=%s allCompleted=true", forgeState.Feature)
90	
91		// Consume the state — clear it before proceeding
92		_ = feature.ClearForgeState(projectRoot)
93	
94		indexPath := filepath.Join(projectRoot, feature.GetFeatureIndexFile(featureSlug))
95		index, err := task.LoadIndex(indexPath)
96		if err != nil {
97			Debugf(verbose, "index.json not found: %s (%v)", indexPath, err)
98			return nil, nil
99		}
100		Debugf(verbose, "loaded index: %d tasks", index.TaskCount())
101	
102		// All tasks must be completed or skipped (rejected does not count as done)
103		for _, t := range index.TasksMap() {
104			if t.Status != feature.StatusCompleted && t.Status != feature.StatusSkipped {
105				Debugf(verbose, "task %s is %s — not all done", t.ID, t.Status)
106				return nil, nil
107			}
108		}
109	
110		return &AllCompletedResult{
111			FeatureSlug: featureSlug,
112			ProjectRoot: projectRoot,
113			DocsOnly:    isDocsOnly(index),
114		}, nil
115	}
116	
117	// isDocsOnly returns true if no task has a testable runtime behavior type.
118	// Docs-only features change only markdown files — no compile/test needed.
119	// Unlike needsTestPipeline in pkg/task, this checks ALL tasks including auto-generated ones.
120	func isDocsOnly(index *task.TaskIndex) bool {
121		for _, t := range index.TasksMap() {
122			if task.IsTestableType(t.Type) {
123				return false
124			}
125		}
126		return true
127	}
128	
129	func runQualityGate(_ *cobra.Command, _ []string) error {
130		result, err := checkAllCompleted(qualityGateVerbose)
131		if err != nil {
132			base.Exit(err)
133		}
134		if result == nil {
135			return nil // not all done is normal, exit silently
136		}
137	
138		fmt.Fprintf(os.Stderr, "=== All tasks completed for feature: %s ===\n", result.FeatureSlug)
139	
140		// Docs-only features have no code changes — skip compile/test gates.
141		if result.DocsOnly {
142			fmt.Fprintln(os.Stderr, "Feature is docs-only — skipping quality gate (no implementation or fix tasks)")
143			os.Exit(0)
144		}
145	
146		// Warn if feature test scripts exist but haven't been promoted.
147		e2eScriptsDir := feature.GetE2EStagingDir(result.ProjectRoot, result.FeatureSlug)
148		markerPath := feature.GetE2EGraduatedMarker(result.ProjectRoot, result.FeatureSlug)
149		if just.FileExists(e2eScriptsDir) && !just.FileExists(markerPath) {
150			fmt.Fprintln(os.Stderr,
151				"WARNING: feature test scripts exist but haven't been run or promoted.\n"+
152					"  Add T-test-run (run-test) to your task index,\n"+
153					"  or run /run-tests to promote and run test scripts manually.")
154		}
155	
156		// Step 1: Quality gate (compile -> fmt -> lint)
157		// Stops at first blocking failure.
158		gateSteps := just.NonBreakingGateSequence()
159		var gateBlockErr error
160		just.RunGate(result.ProjectRoot, "", gateSteps, func(step, output string) {
161			fmt.Fprintf(os.Stderr, "ERROR: %s check failed\n", step)
162			errorDocPath := "tests/results/unit-raw-output.txt"
163			if output != "" {
164				if err := testrunner.WriteUnitTestRawOutput(result.ProjectRoot, "=== "+step+" failure ===\n"+output); err != nil {
165					fmt.Fprintf(os.Stderr, "WARNING: failed to write %s output: %v\n", step, err)
166				}
167			}
168			fixID, fixErr := addFixTask(result.ProjectRoot, result.FeatureSlug, step, output, errorDocPath)
169			if fixErr != nil {
170				fmt.Fprintf(os.Stderr, "WARNING: %v\n", fixErr)
171			}
172			gateBlockErr = handleGateFailure(step, errorDocPath, fixID, just.ExtractConciseError(output, 5), fixTypeFromStep(step) == task.TypeCodingFix)
173		})
174		if gateBlockErr != nil {
175			os.Exit(0)
176		}
177	
178		// Step 2: Project-wide unit tests (with retry-once policy)
179		fmt.Fprintln(os.Stderr, "--- Running project-wide tests ---")
180		unitPassed, unitFixID, unitErr := runUnitTestStep(
181			result.ProjectRoot, result.FeatureSlug,
182			testrunner.RunProjectTests,
183		)
184		if unitErr != nil {
185			fmt.Fprintf(os.Stderr, "WARNING: %v\n", unitErr)
186		}
187		if !unitPassed {
188			unitOutput := "" // output already written by runUnitTestStep
189			errorDocPath := "tests/results/unit-raw-output.txt"
190			if err := handleGateFailure("unit-test", errorDocPath, unitFixID, just.ExtractConciseError(unitOutput, 5), true); err != nil {
191				os.Exit(0)
192			}
193		}
194	
195		// Step 3: Full test regression (promoted scripts in tests/e2e/)
196		if err := runTestRegression(result.ProjectRoot, result.FeatureSlug); err != nil {
197			os.Exit(0)
198		}
199		return nil
200	}
201	
202	// runTestRegression runs the full test regression suite when a justfile with
203	// a test recipe is present. When surfaces are configured in .forge/config.yaml,
204	// it orchestrates per-surface lifecycle (dev→probe→test→teardown for web/api/mobile;
205	// test→teardown for cli/tui). Falls back to legacy behavior when no surfaces configured.
206	// Returns an error when a gate failure is detected, nil otherwise.
207	func runTestRegression(projectRoot, featureSlug string) error {
208		if !just.HasJustfile(projectRoot) || !just.HasRecipe(projectRoot, "test") {
209			return nil
210		}
211	
212		// Detect surface types from config.
213		surfaces, _ := forgeconfig.ReadSurfaces(projectRoot)
214		surfaceTypes := forgeconfig.SurfaceTypes(surfaces)
215	
216		if len(surfaceTypes) == 0 {
217			// No surfaces configured — fall back to legacy behavior.
218			return runTestRegressionLegacy(projectRoot, featureSlug)
219		}
220	
221		// Surface-aware orchestration: run lifecycle per surface type.
222		return runTestRegressionSurface(projectRoot, featureSlug, surfaceTypes)
223	}
224	
225	// runTestRegressionLegacy is the pre-surface-aware test regression logic.
226	// Runs test-setup (optional), e2eprobe health check, then just test.
227	func runTestRegressionLegacy(projectRoot, featureSlug string) error {
228		// Optional setup step — skip regression on failure.
229		if just.HasRecipe(projectRoot, "test-setup") {
230			fmt.Fprintln(os.Stderr, "--- Ensuring test dependencies (just test-setup) ---")
231			setupOutput, setupSuccess := just.RunCapture(projectRoot, "just", "test-setup")
232			if !setupSuccess {
233				fmt.Fprintln(os.Stderr, "WARNING: test-setup failed; skipping test regression")
234				fmt.Fprintln(os.Stderr, "  To retry manually: just test-setup && just test")
235				if setupOutput != "" {
236					if err := testrunner.WriteRegressionRawOutput(projectRoot, "=== test-setup failure ===\n"+setupOutput); err != nil {
237						fmt.Fprintf(os.Stderr, "WARNING: failed to write setup output: %v\n", err)
238					} else {
239						fmt.Fprintln(os.Stderr, "  Setup output saved to tests/results/raw-output.txt")
240					}
241				}
242				return nil
243			}
244		}
245	
246		// Health check — skip regression if servers aren't ready.
247		if !e2eprobe.ProbeServers(projectRoot, "") {
248			fmt.Fprintln(os.Stderr, "WARNING: server health check failed; skipping test regression")
249			fmt.Fprintln(os.Stderr, "  Start dev server and retry: just dev && just test")
250			return nil
251		}
252	
253		// Run the regression suite.
254		fmt.Fprintln(os.Stderr, "--- Running full test regression (just test) ---")
255		regressionOutput, regSuccess := just.RunCapture(projectRoot, "just", "test")
256		if !regSuccess {
257			fmt.Fprintln(os.Stderr, "ERROR: test regression failed")
258			errorDocPath := "tests/results/raw-output.txt"
259			if regressionOutput != "" {
260				if err := testrunner.WriteRegressionRawOutput(projectRoot, regressionOutput); err != nil {
261					fmt.Fprintf(os.Stderr, "WARNING: failed to write raw-output.txt: %v\n", err)
262				}
263			}
264			fixID, fixErr := addFixTask(projectRoot, featureSlug, "test", regressionOutput, errorDocPath)
265			if fixErr != nil {
266				fmt.Fprintf(os.Stderr, "WARNING: %v\n", fixErr)
267			}
268			return handleGateFailure("test", errorDocPath, fixID, just.ExtractConciseError(regressionOutput, 5), true)
269		}
270		return nil
271	}
272	
273	// runTestRegressionSurface orchestrates per-surface-type lifecycle sequences.
274	// For each unique surface type, runs the appropriate sequence:
275	//   - web/api/mobile: dev → probe → test → teardown (full lifecycle)
276	//   - cli/tui: test → teardown (simplified)
277	//
278	// Surfaces of the same type share a single lifecycle (dev/probe run once per type).
279	// Teardown is mandatory regardless of prior step success/failure.
280	func runTestRegressionSurface(projectRoot, featureSlug string, surfaceTypes []string) error {
281		var lastErr error
282		for _, surfaceType := range surfaceTypes {
283			fmt.Fprintf(os.Stderr, "--- Running surface orchestration for %s ---\n", surfaceType)
284			result := runSurfaceLifecycle(projectRoot, surfaceType)
285			if !result.success {
286				errorDocPath := "tests/e2e/results/raw-output.txt"
287				if result.output != "" {
288					if err := testrunner.WriteRegressionRawOutput(projectRoot, result.output); err != nil {
289						fmt.Fprintf(os.Stderr, "WARNING: failed to write raw-output.txt: %v\n", err)
290					}
291				}
292				fixID, fixErr := addFixTask(projectRoot, featureSlug, "test", result.output, errorDocPath)
293				if fixErr != nil {
294					fmt.Fprintf(os.Stderr, "WARNING: %v\n", fixErr)
295				}
296				lastErr = handleGateFailure("test", errorDocPath, fixID, just.ExtractConciseError(result.output, 5), true)
297			}
298		}
299		return lastErr
300	}
301	
302	// lifecycleResult holds the result of a surface lifecycle execution.
303	type lifecycleResult struct {
304		success bool
305		output  string
306	}
307	
308	// needsFullLifecycle returns true for surface types that require dev→probe→test→teardown.
309	// cli and tui surfaces use the simplified test→teardown sequence.
310	func needsFullLifecycle(surfaceType string) bool {
311		return surfaceType == "web" || surfaceType == "api" || surfaceType == "mobile"
312	}
313	
314	// resolveRecipe attempts to find a surface-specific recipe (e.g., "web-dev"),
315	// falling back to the generic recipe (e.g., "dev") if not found.
316	// Returns the recipe name to use, or empty string if neither exists.
317	func resolveRecipe(projectRoot, surfaceType, genericRecipe string) string {
318		specificRecipe := surfaceType + "-" + genericRecipe
319		if just.HasRecipe(projectRoot, specificRecipe) {
320			return specificRecipe
321		}
322		if just.HasRecipe(projectRoot, genericRecipe) {
323			return genericRecipe
324		}
325		return ""
326	}
327	
328	// runSurfaceLifecycle executes the per-surface lifecycle sequence.
329	// For web/api/mobile: dev → probe → test → teardown
330	// For cli/tui: test → teardown
331	// Teardown always executes (via defer-like pattern).
332	func runSurfaceLifecycle(projectRoot, surfaceType string) lifecycleResult {
333		full := needsFullLifecycle(surfaceType)
334	
335		// Phase 1: Dev (full lifecycle only)
336		if full {
337			recipe := resolveRecipe(projectRoot, surfaceType, "dev")
338			if recipe != "" {
339				fmt.Fprintf(os.Stderr, "  Starting dev server (just %s)...\n", recipe)
340				output, success := just.RunCapture(projectRoot, "just", recipe)
341				if !success {
342					fmt.Fprintf(os.Stderr, "  ERROR: dev failed (just %s)\n", recipe)
343					runTeardown(projectRoot, surfaceType)
344					return lifecycleResult{success: false, output: output}
345				}
346			}
347		}
348	
349		// Phase 2: Probe (full lifecycle only)
350		if full {
351			probeRecipe := resolveRecipe(projectRoot, surfaceType, "probe")
352			if !probeWithRetry(projectRoot, probeRecipe, 3, 5*time.Second) {
353				fmt.Fprintln(os.Stderr, "  ERROR: probe failed after retries")
354				runTeardown(projectRoot, surfaceType)
355				return lifecycleResult{success: false, output: "probe failed: server not responding after 3 retries"}
356			}
357		}
358	
359		// Phase 3: Test
360		var result lifecycleResult
361		testRecipe := resolveRecipe(projectRoot, surfaceType, "test")
362		if testRecipe != "" {
363			fmt.Fprintf(os.Stderr, "  Running tests (just %s)...\n", testRecipe)
364			output, success := just.RunCapture(projectRoot, "just", testRecipe)
365			result = lifecycleResult{success: success, output: output}
366			if !success {
367				fmt.Fprintln(os.Stderr, "  ERROR: test failed")
368			}
369		} else {
370			result = lifecycleResult{success: true}
371		}
372	
373		// Phase 4: Teardown (always)
374		runTeardown(projectRoot, surfaceType)
375	
376		return result
377	}
