379	// runTeardown executes the teardown recipe for a surface type.
380	// Errors are logged but never fail the lifecycle — teardown is best-effort cleanup.
381	func runTeardown(projectRoot, surfaceType string) {
382		recipe := resolveRecipe(projectRoot, surfaceType, "teardown")
383		if recipe != "" {
384			fmt.Fprintf(os.Stderr, "  Running teardown (just %s)...\n", recipe)
385			output, success := just.RunCapture(projectRoot, "just", recipe)
386			if !success {
387				fmt.Fprintf(os.Stderr, "  WARNING: teardown failed (just %s)\n", recipe)
388				if output != "" {
389					fmt.Fprintf(os.Stderr, "  %s\n", just.ExtractConciseError(output, 3))
390				}
391			}
392		}
393	}
