395	// probeWithRetry runs the probe recipe with the specified number of retries.
396	// Returns true if the probe succeeds within the retry count.
397	// Returns true (skip) if the probe recipe doesn't exist.
398	// interval is the delay between retries (0 for no delay, useful in tests).
399	func probeWithRetry(projectRoot, probeRecipe string, maxRetries int, interval time.Duration) bool {
400		if probeRecipe == "" {
401			return true // no probe recipe — skip
402		}
403	
404		// Verify the recipe actually exists before retrying.
405		if !just.HasRecipe(projectRoot, probeRecipe) {
406			return true // recipe not found — skip
407		}
408	
409		for attempt := range maxRetries {
410			if attempt > 0 && interval > 0 {
411				fmt.Fprintf(os.Stderr, "  Probe retry %d/%d (waiting %v)...\n", attempt+1, maxRetries, interval)
412				time.Sleep(interval)
413			}
414			fmt.Fprintf(os.Stderr, "  Probing (just %s) attempt %d/%d...\n", probeRecipe, attempt+1, maxRetries)
415			_, success := just.RunCapture(projectRoot, "just", probeRecipe)
416			if success {
417				fmt.Fprintln(os.Stderr, "  Probe succeeded")
418				return true
419			}
420		}
421		return false
422	}
