427	// breaking indicates whether the fix task blocks downstream tasks.
428	func handleGateFailure(step, errorDocPath, fixID, concise string, breaking bool) error {
429		action := "run `forge task add --type coding.fix` to create one manually, then `forge task claim`"
430		if fixID != "" {
431			action = "run `forge task claim` to pick it up"
432		}
433	
434		guide := map[string]string{
435			"compile":   "fix compilation errors",
436			"lint":      "fix lint errors",
437			"unit-test": "fix failing unit tests",
438			"test":      "fix failing tests",
439		}
440		label := map[string]string{
441			"compile":   "Project compilation",
442			"lint":      "Lint check",
443			"unit-test": "Unit tests",
444			"test":      "Advanced tests",
445		}
446	
447		g := guide[step]
448		if g == "" {
449			g = "fix the issue"
450		}
451		l := label[step]
452		if l == "" {
453			l = testrunner.Capitalize(step) + " check"
454		}
455	
456		var fixMsg string
457		if fixID != "" {
458			fixMsg = fmt.Sprintf("Fix task %s added (P0, breaking=%v)", fixID, breaking)
459		} else {
