474	// runUnitTestStep runs unit tests with a retry-once policy for transient failures.
475	// On first failure, tests are re-run once. If retry passes, a warning is logged and
476	// no fix task is created. If retry also fails, a fix task is created with both outputs.
477	// Returns (passed, fixTaskID, error).
478	func runUnitTestStep(projectRoot, featureSlug string, runTest testRunFunc) (bool, string, error) {
479		unitOutput, unitSuccess := runTest(projectRoot)
480		if unitSuccess {
481			return true, "", nil
482		}
483	
484		// First attempt failed — retry once.
485		fmt.Fprintln(os.Stderr, "WARNING: unit tests failed on first attempt, retrying once...")
486		retryOutput, retrySuccess := runTest(projectRoot)
487		if retrySuccess {
488			fmt.Fprintln(os.Stderr, "WARNING: unit tests passed on retry (transient failure)")
489			return true, "", nil
490		}
491	
492		// Both attempts failed — write combined output and create fix task.
493		fmt.Fprintln(os.Stderr, "ERROR: unit tests failed (retried once, both attempts failed)")
494		errorDocPath := "tests/results/unit-raw-output.txt"
495		combinedOutput := fmt.Sprintf(
496			"retried once, both attempts failed\n\n=== First attempt ===\n%s\n\n=== Retry attempt ===\n%s",
497			unitOutput, retryOutput,
498		)
499		if combinedOutput != "" {
500			if err := testrunner.WriteUnitTestRawOutput(projectRoot, combinedOutput); err != nil {
501				fmt.Fprintf(os.Stderr, "WARNING: failed to write unit test output: %v\n", err)
502			}
503		}
504	
505		fixID, fixErr := addFixTask(projectRoot, featureSlug, "unit-test", combinedOutput, errorDocPath)
506		return false, fixID, fixErr
507	}
