509	// inferSurface attempts to determine the surface-key and surface-type for a
510	// fix-task by querying forge surfaces with all extracted source file paths.
511	// Returns ("", "") on any failure (no surfaces configured, no match, parse error)
512	// — the caller falls back to empty values and fix-task creation proceeds unblocked.
513	// Uses all source files (not just the first) to correctly handle multi-surface projects
514	// where different files may belong to different surfaces.
515	func inferSurface(projectRoot, sourceFiles string) (surfaceKey, surfaceType string) {
516		surfaces, err := forgeconfig.ReadSurfaces(projectRoot)
517		if err != nil || len(surfaces) == 0 {
518			return "", ""
519		}
520	
521		// Parse all source file paths from the comma-separated list.
522		// sourceFiles may be "See error output for affected files" when no files found.
523		if sourceFiles == "" || strings.HasPrefix(sourceFiles, "See error") {
524			return "", ""
525		}
526	
527		var files []string
528		for _, part := range strings.Split(sourceFiles, ",") {
529			f := strings.TrimSpace(part)
530			if f != "" {
531				files = append(files, f)
532			}
533		}
534		if len(files) == 0 {
535			return "", ""
536		}
537	
538		// Try each file until one matches a configured surface.
539		for _, file := range files {
540			match, err := forgeconfig.MatchSurface(surfaces, file)
541			if err == nil {
542				return match.Key, match.Type
543			}
544		}
545		return "", ""
546	}
547	
548	// sourceFileRe matches source file paths followed by :line or :line:col patterns.
549	var sourceFileRe = regexp.MustCompile(`([\w][\w./-]*\.\w{1,10})(?::\d+){1,2}`)
550	
551	// sourceExts is a whitelist of source code extensions for file extraction.
552	var sourceExts = map[string]bool{
553		".go": true, ".ts": true, ".js": true, ".tsx": true, ".jsx": true,
554		".py": true, ".rs": true, ".java": true, ".rb": true,
555		".c": true, ".cpp": true, ".h": true, ".hpp": true,
556		".css": true, ".scss": true, ".html": true, ".sql": true,
557		".vue": true, ".svelte": true,
558	}
559	
560	// extractSourceFiles parses error output and returns comma-separated file paths.
561	func extractSourceFiles(output string) string {
562		seen := make(map[string]bool)
563		var files []string
564		for _, match := range sourceFileRe.FindAllStringSubmatch(output, -1) {
565			path := strings.TrimPrefix(match[1], "./")
566			if path == "" || seen[path] {
567				continue
568			}
569			if !sourceExts[filepath.Ext(path)] {
570				continue
571			}
572			seen[path] = true
573			files = append(files, path)
574		}
575	
576		if len(files) > 10 {
577			files = files[:10]
578		}
579		if len(files) == 0 {
580			return "See error output for affected files"
581		}
582		return strings.Join(files, ", ")
583	}
