585	// countFixTasks counts active (non-terminal) fix-tasks for a step.
586	// A fix-task is identified by having a title with the prefix "fix <step>:".
587	// Terminal statuses (completed, rejected, skipped) are excluded from the count.
588	// This ensures the fix-task cap reflects work-in-progress only.
589	func countFixTasks(index *task.TaskIndex, step string) int {
590		count := 0
591		prefix := "fix " + step + ":"
592		for _, t := range index.TasksMap() {
593			if !strings.HasPrefix(t.Title, prefix) {
594				continue
595			}
596			// Exclude terminal statuses
597			if t.Status == "completed" || t.Status == "rejected" || t.Status == "skipped" {
598				continue
599			}
600			count++
601		}
602		return count
603	}
