605	// fixTypeFromStep returns the deterministic task type for a quality gate failure step.
606	// compile/test failures → TypeCodingFix, fmt/lint failures → TypeCodingCleanup.
607	func fixTypeFromStep(step string) string {
608		switch step {
609		case "compile", "unit-test", "test":
610			return task.TypeCodingFix
611		case "fmt", "lint":
612			return task.TypeCodingCleanup
613		default:
614			return task.TypeCodingFix
615		}
616	}
