618	// addFixTask creates fix tasks grouped by test suite (directory) using the same
619	// internal API as `forge task add`. Source files are extracted from the output and
620	// grouped by directory. Each directory group becomes a separate fix-task, enabling
621	// parallel execution and bounded scope. Returns the first task ID on success.
622	// Returns ("", error) on failure: template not found, task add failure, markdown creation failure, or cap exceeded.
623	func addFixTask(projectRoot, featureSlug, step, output, errorDocPath string) (string, error) {
624		sourceFiles := extractSourceFiles(output)
625	
626		// Group source files by directory for parallel execution.
627		groups := groupFilesByDir(sourceFiles)
628	
629		// If no meaningful groups (e.g. "See error output" fallback), create a single task.
630		if len(groups) == 0 {
631			return addSingleFixTask(projectRoot, featureSlug, step, sourceFiles, output, errorDocPath)
632		}
633	
634		// One task per directory group.
635		var firstID string
636		for _, group := range groups {
637			id, err := addSingleFixTask(projectRoot, featureSlug, step, group, output, errorDocPath)
638			if err != nil {
639				// If a group fails (e.g. cap reached), return the error.
640				// Already-created tasks remain in the index.
641				return firstID, err
642			}
643			if firstID == "" {
644				firstID = id
645			}
646		}
647		return firstID, nil
648	}
649	
650	// groupFilesByDir splits comma-separated source files into groups by directory.
651	// Files in the same directory stay in one group. Returns nil if files is empty
652	// or the fallback message.
653	func groupFilesByDir(files string) []string {
654		if files == "" || strings.HasPrefix(files, "See error") {
655			return nil
656		}
657	
658		dirMap := make(map[string][]string)
659		for _, f := range strings.Split(files, ",") {
660			f = strings.TrimSpace(f)
661			if f == "" {
662				continue
663			}
664			dir := filepath.Dir(f)
665			dirMap[dir] = append(dirMap[dir], f)
666		}
667	
668		if len(dirMap) <= 1 {
669			// All files in one directory (or no files) — single group.
670			return nil
671		}
672	
673		var groups []string
674		for _, dirFiles := range dirMap {
675			groups = append(groups, strings.Join(dirFiles, ", "))
676		}
677		return groups
678	}
679	
680	// addSingleFixTask creates a single fix task using the same internal API as `forge task add`.
681	// Mirrors executeAdd() from add.go: template defaults -> AddTask -> CreateTaskMarkdown -> EnsureForgeState.
682	// Returns (taskID, nil) on success.
683	// Returns ("", error) on failure: template not found, task add failure, markdown creation failure, or cap exceeded.
684	func addSingleFixTask(projectRoot, featureSlug, step, sourceFiles, output, errorDocPath string) (string, error) {
685		indexPath := filepath.Join(projectRoot, feature.GetFeatureIndexFile(featureSlug))
686	
687		// Check cap before creating a new fix-task.
688		index, err := task.LoadIndex(indexPath)
689		if err != nil {
690			fmt.Fprintf(os.Stderr, "WARNING: failed to load index for cap check: %v\n", err)
691			// Proceed without cap check if index can't be loaded.
692		} else {
693			active := countFixTasks(index, step)
694			if active >= maxFixTasksPerStep {
695				fmt.Fprintf(os.Stderr, "max fix-tasks reached for %s, manual intervention required\n", step)
696				return "", ErrMaxFixTasks
697			}
698		}
699	
700		// Infer surface-key/type from the first extracted source file path.
701		// Falls back to empty strings on any failure (no surfaces, no match, etc.)
702		// so fix-task creation is never blocked by surface inference failure.
703		surfaceKey, surfaceType := inferSurface(projectRoot, sourceFiles)
704	
705		testScript := "just " + step
706	
707		title := fmt.Sprintf("fix %s: %s failure in quality gate", step, testScript)
708		description := fmt.Sprintf(
709			"Quality gate step `%s` failed during quality-gate hook.\n\n"+
710				"Error output saved to: `%s`\n\n"+
711				"Concise error:\n```\n%s\n```",
712			testScript, errorDocPath, just.ExtractConciseError(output, 10),
713		)
714	
715		// Build opts — Priority/Breaking/EstimatedTime sourced from template defaults
716		// when available (dual-source truth: opts is authoritative, template provides defaults).
717		// SourceTaskID is deliberately empty (project-wide gate has no source task).
718		// Vars["SOURCE_TASK_ID"] is "N/A (project-wide gate)" for template rendering.
719		taskType := fixTypeFromStep(step)
720	
721		// Derive Breaking and EstimatedTime from template defaults (dual-source truth).
722		// For coding.cleanup (fmt/lint failures): Breaking=false, EstimatedTime="15min".
723		// For coding.fix (compile/test failures): Breaking=true, EstimatedTime="30min".
724		breaking := true
725		estimatedTime := "30min"
726		if defs, err := tmpl.GetDefaults(taskType); err == nil {
727			breaking = defs.Breaking
728			estimatedTime = defs.EstimatedTime
729		}
730	
731		opts := task.AddTaskOpts{
732			Title:         title,
733			Priority:      "P0",
734			EstimatedTime: estimatedTime,
735			Breaking:      breaking,
736			Description:   description,
737			Template:      taskType,
738			Type:          taskType,
739			SurfaceKey:    surfaceKey,
740			SurfaceType:   surfaceType,
741			Vars: map[string]string{
742				"SOURCE_FILES":   sourceFiles,
743				"TEST_SCRIPT":    testScript,
744				"TEST_RESULTS":   errorDocPath,
745				"SOURCE_TASK_ID": "N/A (project-wide gate)",
746			},
747		}
748	
749		tasksDir := filepath.Join(projectRoot, feature.GetFeatureTasksDir(featureSlug))
750	
751		if _, err := tmpl.Get(opts.Template); err != nil {
752			return "", fmt.Errorf("template %q not found: %w", opts.Template, err)
753		}
754		if defs, err := tmpl.GetDefaults(opts.Template); err == nil && defs.IDPrefix != "" {
755			opts.IDPrefix = defs.IDPrefix
756		}
757	
758		id, err := task.AddTask(indexPath, opts)
759		if err != nil {
760			return "", fmt.Errorf("failed to add fix task: %w", err)
761		}
762	
763		opts.ID = id
764	
765		if err := task.CreateTaskMarkdown(tasksDir, id+".md", opts); err != nil {
766			return "", fmt.Errorf("failed to create fix task file %s: %w", id+".md", err)
767		}
768	
769		if err := feature.EnsureForgeState(projectRoot, featureSlug); err != nil {
770			fmt.Fprintf(os.Stderr, "WARNING: failed to update .forge/state.json: %v\n", err)
771		}
772	
773		fmt.Fprintf(os.Stderr, "Fix task %s added (P0, breaking=%v)\n", id, breaking)
774		return id, nil
775	}
