15	// ProbeEndpoint checks if an HTTP endpoint responds with status < 500.
16	func ProbeEndpoint(url string, timeout time.Duration) bool {
17		client := http.Client{Timeout: timeout}
18		resp, err := client.Get(url)
19		if err != nil {
20			return false
21		}
22		defer func() { _ = resp.Body.Close() }()
23		return resp.StatusCode < 500
24	}
