26	// ProbeServers reads tests/e2e/config.yaml and probes baseUrl/apiBaseUrl.
27	// Returns true if all configured endpoints respond, or if no config exists.
28	// path is the health check path appended to each URL (defaults to "/health").
29	func ProbeServers(projectRoot, path string) bool {
30		if path == "" {
31			path = "/health"
32		}
33	
34		configPath := filepath.Join(projectRoot, "tests", "e2e", "config.yaml")
35		if !just.FileExists(configPath) {
36			fmt.Fprintln(os.Stderr, "OK: CLI-only project")
37			return true
38		}
39	
40		data, err := os.ReadFile(configPath)
41		if err != nil {
42			fmt.Fprintf(os.Stderr, "  WARNING: cannot read config.yaml: %v\n", err)
43			return true
44		}
45	
46		baseURL := ExtractYAMLStringField(data, "baseUrl")
47		apiBaseURL := ExtractYAMLStringField(data, "apiBaseUrl")
48	
49		endpoints := []string{}
50		if baseURL != "" {
51			endpoints = append(endpoints, baseURL)
52		}
53		if apiBaseURL != "" {
54			endpoints = append(endpoints, apiBaseURL)
55		}
56		if len(endpoints) == 0 {
57			fmt.Fprintln(os.Stderr, "OK: CLI-only project")
58			return true
59		}
60	
61		probeTimeout := 5 * time.Second
62		for _, ep := range endpoints {
63			probeURL := strings.TrimRight(ep, "/") + path
64			if !ProbeEndpoint(probeURL, probeTimeout) {
65				fmt.Fprintf(os.Stderr, "FAIL: %s not responding\n", probeURL)
66				return false
67			}
68			fmt.Fprintf(os.Stderr, "OK: %s\n", probeURL)
69		}
70		return true
71	}
