73	// ExtractYAMLStringField extracts a top-level string field from simple YAML.
74	func ExtractYAMLStringField(data []byte, field string) string {
75		for line := range strings.SplitSeq(string(data), "\n") {
76			line = strings.TrimSpace(line)
77			if after, ok := strings.CutPrefix(line, field+":"); ok {
78				val := strings.TrimSpace(after)
79				val = strings.Trim(val, `'"`)
80				return val
81			}
82		}
83		return ""
84	}
