12	func TestProbeEndpoint(t *testing.T) {
13		t.Run("unreachable returns false", func(t *testing.T) {
14			if ProbeEndpoint("http://127.0.0.1:1", 100*time.Millisecond) {
15				t.Error("expected false for unreachable endpoint")
16			}
17		})
18	
19		t.Run("success returns true", func(t *testing.T) {
20			ts := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
21				w.WriteHeader(http.StatusOK)
22			}))
23			defer ts.Close()
24	
25			if !ProbeEndpoint(ts.URL, 2*time.Second) {
26				t.Error("expected true for healthy endpoint")
27			}
28		})
29	
30		t.Run("server error returns false", func(t *testing.T) {
31			ts := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
32				w.WriteHeader(http.StatusInternalServerError)
33			}))
34			defer ts.Close()
35	
36			if ProbeEndpoint(ts.URL, 2*time.Second) {
37				t.Error("expected false for 500 status")
38			}
39		})
40	}
