162	func TestExtractYAMLStringField(t *testing.T) {
163		tests := []struct {
164			name  string
165			data  string
166			field string
167			want  string
168		}{
169			{"found", "baseUrl: http://localhost:3000\napiBaseUrl: http://localhost:8080\n", "baseUrl", "http://localhost:3000"},
170			{"quoted", "baseUrl: 'http://localhost:3000'\n", "baseUrl", "http://localhost:3000"},
171			{"double quoted", "baseUrl: \"http://localhost:3000\"\n", "baseUrl", "http://localhost:3000"},
172			{"missing field", "other: value\n", "baseUrl", ""},
173			{"empty data", "", "baseUrl", ""},
174			{"field with spaces", "apiBaseUrl:   http://api:8080  \n", "apiBaseUrl", "http://api:8080"},
175		}
176		for _, tc := range tests {
177			t.Run(tc.name, func(t *testing.T) {
178				got := ExtractYAMLStringField([]byte(tc.data), tc.field)
179				if got != tc.want {
180					t.Errorf("got %q, want %q", got, tc.want)
181				}
182			})
183		}
184	}
